 {"id":"charmed_rust-nq6","title":"[PropTest] Add roundtrip invariant tests","description":"## Parent Epic
charmed_rust-dnt: [PropTest] Property-based testing for input parsing

## Objective
Implement roundtrip invariant tests that verify parse -> serialize -> parse cycles produce identical results, ensuring the parsing and serialization code are consistent with each other.

## Detailed Requirements

### 1. Key Roundtrip Properties

```rust
use proptest::prelude::*;
use crate::key::{Key, KeyParser, KeySerializer};

proptest! {
    /// Property: parse(serialize(key)) == key for all valid keys
    #[test]
    fn key_roundtrip_parse_serialize(
        key in arb_serializable_key()
    ) {
        // Skip keys that can't be serialized (e.g., Unknown)
        prop_assume!(key.is_serializable());

        let bytes = KeySerializer::serialize(&key);
        let parsed = KeyParser::parse(&bytes);

        prop_assert!(parsed.is_some(), "Serialized key should parse");
        let (roundtrip_key, consumed) = parsed.unwrap();

        prop_assert_eq!(
            consumed, bytes.len(),
            "Should consume all serialized bytes"
        );
        prop_assert_eq!(
            roundtrip_key, key,
            "Roundtrip should preserve key identity"
        );
    }

    /// Property: serialize(parse(bytes)) produces equivalent bytes for valid sequences
    #[test]
    fn key_roundtrip_serialize_parse(
        seq in arb_canonical_key_sequence()
    ) {
        let original_bytes = seq.to_bytes();

        // Parse the original
        let parsed = KeyParser::parse(&original_bytes);
        prop_assert!(parsed.is_some());
        let (key, _) = parsed.unwrap();

        // Serialize back
        let reserialized = KeySerializer::serialize(&key);

        // Parse again
        let reparsed = KeyParser::parse(&reserialized);
        prop_assert!(reparsed.is_some());
        let (roundtrip_key, _) = reparsed.unwrap();

        // Keys should be equal (bytes may differ for non-canonical forms)
        prop_assert_eq!(key, roundtrip_key);
    }
}
```

### 2. Mouse Event Roundtrip Properties

```rust
proptest! {
    /// Property: parse(serialize(event)) == event for all valid mouse events
    #[test]
    fn mouse_roundtrip_parse_serialize(
        event in arb_mouse_event()
    ) {
        let bytes = MouseSerializer::serialize(&event);
        let parsed = MouseParser::parse(&bytes);

        prop_assert!(parsed.is_some(), "Serialized event should parse");
        let (roundtrip_event, consumed) = parsed.unwrap();

        prop_assert_eq!(consumed, bytes.len());
        prop_assert_eq!(roundtrip_event.button, event.button);
        prop_assert_eq!(roundtrip_event.x, event.x);
        prop_assert_eq!(roundtrip_event.y, event.y);
        prop_assert_eq!(roundtrip_event.modifiers(), event.modifiers());
    }

    /// Property: SGR format roundtrip preserves all fields
    #[test]
    fn sgr_roundtrip_complete(
        event in arb_sgr_mouse_event()
    ) {
        let bytes = event.to_bytes();
        let (parsed, _) = MouseParser::parse(&bytes).unwrap();
        let reserialized = parsed.to_sgr_bytes();
        let (reparsed, _) = MouseParser::parse(&reserialized).unwrap();

        prop_assert_eq!(parsed.button, reparsed.button);
        prop_assert_eq!(parsed.x, reparsed.x);
        prop_assert_eq!(parsed.y, reparsed.y);
        prop_assert_eq!(parsed.is_release(), reparsed.is_release());
        prop_assert_eq!(parsed.is_motion(), reparsed.is_motion());
