## Objective
Implement an HTML/CSS output backend that generates styled HTML elements instead of ANSI escape codes, enabling charmed_rust styles to be rendered correctly in web browsers.

## Detailed Requirements

### 1. Implement HtmlBackend

```rust
// crates/lipgloss/src/backend/html.rs

use super::OutputBackend;
use crate::{Border, Color, Style};

pub struct HtmlBackend {
    /// Whether to use inline styles or CSS classes
    pub use_inline_styles: bool,
    /// CSS class prefix for generated classes
    pub class_prefix: String,
}

impl Default for HtmlBackend {
    fn default() -> Self {
        Self {
            use_inline_styles: true,
            class_prefix: "charmed".to_string(),
        }
    }
}

impl OutputBackend for HtmlBackend {
    fn render(&self, content: &str, style: &Style) -> String {
        let css = self.style_to_css(style);
        let escaped = html_escape(content);

        if self.use_inline_styles {
            format!(r#"<span style="{}">{}</span>"#, css, escaped)
        } else {
            let class = self.generate_class_name(style);
            format!(r#"<span class="{}">{}</span>"#, class, escaped)
        }
    }

    fn render_border(&self, content: &str, border: &Border) -> String {
        let border_css = self.border_to_css(border);
        format!(
            r#"<div style="display: inline-block; {}">{}</div>"#,
            border_css,
            content
        )
    }

    fn join(&self, segments: &[String], separator: &str) -> String {
        segments.join(&html_escape(separator))
    }

    fn newline(&self) -> &str {
        "<br>"
    }

    fn measure_width(&self, content: &str) -> usize {
        // Strip HTML tags and measure Unicode width
        strip_html_tags(content).width()
    }
}
```

### 2. CSS Generation

```rust
impl HtmlBackend {
    fn style_to_css(&self, style: &Style) -> String {
        let mut css_parts = Vec::new();

        // Colors
        if let Some(fg) = &style.foreground {
            css_parts.push(format!("color: {}", self.color_to_css(fg)));
        }
        if let Some(bg) = &style.background {
            css_parts.push(format!("background-color: {}", self.color_to_css(bg)));
        }

        // Text decorations
        if style.bold {
            css_parts.push("font-weight: bold".to_string());
        }
        if style.italic {
            css_parts.push("font-style: italic".to_string());
        }
        if style.underline {
            css_parts.push("text-decoration: underline".to_string());
        }
        if style.strikethrough {
            css_parts.push("text-decoration: line-through".to_string());
        }

        // Spacing (converted from character units to em/ch)
        if style.padding.top > 0 || style.padding.bottom > 0 ||
           style.padding.left > 0 || style.padding.right > 0 {
            css_parts.push(format!(
                "padding: {}em {}ch {}em {}ch",
                style.padding.top as f32 * 1.2,
                style.padding.right,
                style.padding.bottom as f32 * 1.2,
                style.padding.left
            ));
        }

        if style.margin.top > 0 || style.margin.bottom > 0 ||
           style.margin.left > 0 || style.margin.right > 0 {
            css_parts.push(format!(
                "margin: {}em {}ch {}em {}ch",
                style.margin.top as f32 * 1.2,
                style.margin.right,
                style.margin.bottom as f32 * 1.2,
                style.margin.left
            ));
        }

        // Display mode for block-level styling
        if style.width.is_some() || style.height.is_some() {
            css_parts.push("display: inline-block".to_string());
        }

        if let Some(width) = style.width {
            css_parts.push(format!("width: {}ch", width));
        }
        if let Some(height) = style.height {
            css_parts.push(format!("height: {}em", height as f32 * 1.2));
        }

        css_parts.join("; ")
    }

    fn color_to_css(&self, color: &Color) -> String {
        match color {
            Color::Rgb(r, g, b) => format!("rgb({}, {}, {})", r, g, b),
            Color::Hex(hex) => format!("#{}", hex),
            Color::Ansi(code) => ansi_to_css_color(*code),
            Color::AdaptiveColor { light, dark } => {
                // Use CSS custom property with fallback
                format!(
                    "var(--charmed-color, {})",
                    self.color_to_css(light)
                )
            }
        }
    }
}
```

### 3. ANSI to CSS Color Mapping

```rust
// crates/lipgloss/src/backend/ansi_colors.rs

/// Map ANSI 256-color codes to CSS colors
pub fn ansi_to_css_color(code: u8) -> String {
    match code {
        // Standard colors (0-7)
        0 => "#000000".to_string(),   // Black
        1 => "#cd0000".to_string(),   // Red
        2 => "#00cd00".to_string(),   // Green
        3 => "#cdcd00".to_string(),   // Yellow
        4 => "#0000ee".to_string(),   // Blue
        5 => "#cd00cd".to_string(),   // Magenta
        6 => "#00cdcd".to_string(),   // Cyan
        7 => "#e5e5e5".to_string(),   // White

        // Bright colors (8-15)
        8 => "#7f7f7f".to_string(),   // Bright Black (Gray)
        9 => "#ff0000".to_string(),   // Bright Red
        10 => "#00ff00".to_string(),  // Bright Green
        11 => "#ffff00".to_string(),  // Bright Yellow
        12 => "#5c5cff".to_string(),  // Bright Blue
        13 => "#ff00ff".to_string(),  // Bright Magenta
        14 => "#00ffff".to_string(),  // Bright Cyan
        15 => "#ffffff".to_string(),  // Bright White

        // 216-color cube (16-231)
        16..=231 => {
            let n = code - 16;
            let r = (n / 36) % 6;
            let g = (n / 6) % 6;
            let b = n % 6;

            let to_hex = |v: u8| if v == 0 { 0 } else { 55 + v * 40 };
            format!("#{:02x}{:02x}{:02x}", to_hex(r), to_hex(g), to_hex(b))
        }

        // Grayscale (232-255)
        232..=255 => {
            let gray = 8 + (code - 232) * 10;
            format!("#{:02x}{:02x}{:02x}", gray, gray, gray)
        }
    }
}
```

### 4. Border Rendering

```rust
impl HtmlBackend {
    fn border_to_css(&self, border: &Border) -> String {
        let mut css_parts = Vec::new();

        // Map border style to CSS
        let border_style = match border.style {
            BorderStyle::Normal => "solid",
            BorderStyle::Rounded => "solid",  // Use border-radius
            BorderStyle::Double => "double",
            BorderStyle::Thick => "solid",    // Use border-width
            BorderStyle::Hidden => "none",
        };

        let width = match border.style {
            BorderStyle::Thick => "3px",
            BorderStyle::Double => "3px",
            _ => "1px",
        };

        css_parts.push(format!("border: {} {} {}", 
            width,
            border_style,
            border.color.as_ref()
                .map(|c| self.color_to_css(c))
                .unwrap_or_else(|| "currentColor".to_string())
        ));

        if matches!(border.style, BorderStyle::Rounded) {
            css_parts.push("border-radius: 0.5em".to_string());
        }

        css_parts.join("; ")
    }
}
```

### 5. HTML Escaping Utilities

```rust
// crates/lipgloss/src/backend/html_utils.rs

/// Escape HTML special characters
pub fn html_escape(content: &str) -> String {
    content
        .replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&#39;")
        .replace('\n', "<br>")
        .replace(' ', "&nbsp;")  // Preserve whitespace
}

/// Strip HTML tags for width measurement
pub fn strip_html_tags(content: &str) -> String {
    let mut result = String::new();
    let mut in_tag = false;

    for ch in content.chars() {
        match ch {
            '<' => in_tag = true,
            '>' => in_tag = false,
            _ if !in_tag => result.push(ch),
            _ => {}
        }
    }

    // Also decode common entities
    result
        .replace("&nbsp;", " ")
        .replace("&lt;", "<")
        .replace("&gt;", ">")
        .replace("&amp;", "&")
        .replace("&quot;", "\"")
        .replace("<br>", "\n")
}
```

